import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"期权卖方","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/options/options-seller.md","filePath":"zh-CN/derivatives/options/options-seller.md"}'),i={name:"derivatives/options/options-seller.md"};function l(h,a,d,n,s,p){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="期权卖方" tabindex="-1">期权卖方 <a class="header-anchor" href="#期权卖方" aria-label="Permalink to &quot;期权卖方&quot;">​</a></h1><p>期权卖方（义务方）通过出售期权合约收取权利金，并在权利方行权时承担履约义务。本页说明卖方的风险收益特征、保证金要求及常见策略。</p><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>期权卖方即义务方，通过卖出期权合约收取权利金，作为回报必须在权利方行使权利时无条件履行义务。核心特征：不享有权利，必须承担履行合约的义务。</p><p>在持仓页面体现为期权空头仓位（期权持仓数量为负数）。</p><h3 id="风险与收益" tabindex="-1">风险与收益 <a class="header-anchor" href="#风险与收益" aria-label="Permalink to &quot;风险与收益&quot;">​</a></h3><ul><li>最大收益：仅限于卖出期权时收取的权利金</li><li>潜在亏损：理论上无限（卖出看涨期权，股价可无限上涨）或极大（卖出看跌期权，股价最低为 0）</li></ul><h3 id="保证金要求" tabindex="-1">保证金要求 <a class="header-anchor" href="#保证金要求" aria-label="Permalink to &quot;保证金要求&quot;">​</a></h3><p>为确保义务方有能力履行合约，需向券商缴纳保证金。市场不利时可能被追加保证金（Margin Call），不足时面临被强制平仓的风险。</p><hr><h2 id="卖出看涨期权-short-call" tabindex="-1">卖出看涨期权（Short Call） <a class="header-anchor" href="#卖出看涨期权-short-call" aria-label="Permalink to &quot;卖出看涨期权（Short Call）&quot;">​</a></h2><p>具有到期以约定行权价卖出正股的义务。如权利方行权，必须以行权价卖出正股。</p><h3 id="盈亏计算" tabindex="-1">盈亏计算 <a class="header-anchor" href="#盈亏计算" aria-label="Permalink to &quot;盈亏计算&quot;">​</a></h3><table tabindex="0"><thead><tr><th>到期情况</th><th>盈亏</th></tr></thead><tbody><tr><td>被行权（价内）</td><td>亏损 =（股票市价 - 行权价 - 权利金）× 股票数</td></tr><tr><td>未被行权（价外到期）</td><td>获得权利金，此为最大收益</td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>以权利金 5 USD 卖出 1 张看涨期权，行权价 50，合约 100 股，获取 500 USD：</p><p><strong>股价 40（市价 &lt; 行权价）</strong><br> 价外，极少被行权 → 获取权利金收益 500 USD</p><p><strong>股价 50（市价 = 行权价）</strong><br> 被行权盈亏 = [-max(50-50,0) + 5] × 100 = 500 USD → 仍获利</p><p><strong>股价 60（市价 &gt; 行权价）</strong><br> 被行权盈亏 = [-max(60-50,0) + 5] × 100 = -500 USD → 亏损</p><h3 id="备兑策略-covered-call" tabindex="-1">备兑策略（Covered Call） <a class="header-anchor" href="#备兑策略-covered-call" aria-label="Permalink to &quot;备兑策略（Covered Call）&quot;">​</a></h3><p>持有足够正股同时卖出看涨期权，可减少或抵消 Short Call 的开仓保证金要求。在期权到期日当天，期权达到价外 2%-5% 以内时正股会被备兑冻结，此时正股不能卖出。</p><hr><h2 id="卖出看跌期权-short-put" tabindex="-1">卖出看跌期权（Short Put） <a class="header-anchor" href="#卖出看跌期权-short-put" aria-label="Permalink to &quot;卖出看跌期权（Short Put）&quot;">​</a></h2><p>具有到期以约定行权价买入正股的义务。如权利方行权，必须以行权价买入正股。</p><h3 id="盈亏计算-1" tabindex="-1">盈亏计算 <a class="header-anchor" href="#盈亏计算-1" aria-label="Permalink to &quot;盈亏计算&quot;">​</a></h3><table tabindex="0"><thead><tr><th>到期情况</th><th>盈亏</th></tr></thead><tbody><tr><td>被行权（价内）</td><td>亏损 =（行权价 - 股票市价 - 权利金）× 股票数</td></tr><tr><td>未被行权（价外到期）</td><td>获得权利金，此为最大收益</td></tr></tbody></table><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>以权利金 5 USD 卖出 1 张看跌期权，行权价 50，合约 100 股，获取 500 USD：</p><p><strong>股价 40（市价 &lt; 行权价）</strong><br> 被行权以 50 USD 买入 100 股，持仓亏损 1,000 USD，权利金收入 500 USD → 综合亏损 500 USD</p><p><strong>股价 50（市价 = 行权价）</strong><br> 被行权买入无持仓盈亏，获取权利金 500 USD → 盈利。未被行权则同样获取 500 USD</p><p><strong>股价 60（市价 &gt; 行权价）</strong><br> 价外，极少被行权 → 获取权利金收益 500 USD</p><hr><h2 id="重要提示" tabindex="-1">重要提示 <a class="header-anchor" href="#重要提示" aria-label="Permalink to &quot;重要提示&quot;">​</a></h2><ul><li>美式期权买方可在到期日前对价内期权提前行权，卖方须配合行权</li><li>卖空期权（Short Options）即使价外仍有可能被行权（特别是正股停牌时）</li><li>Short Call 被行权时，默认使用账户持有的正股交割；若正股不足且该股支持融券，将产生负股票持仓（沽空状态）</li><li>Short Put 被行权时，将以行权价买入对应正股，需账户有足够现金或融资额度</li><li>持有正股空仓时卖出看跌期权可形成 Covered Put，保证金要求有所降低</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/derivatives/options/options-buyer">期权买方</a> — 买方权利特征与盈亏计算</li><li><a href="/wiki/derivatives/options/how-to-buy-options">如何买入期权</a> — 期权链查找与下单操作步骤</li><li><a href="/wiki/margin/margin-requirements">保证金</a> — 期权卖方保证金计算规则</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/derivatives">衍生品</a></li><li><a href="/wiki/derivatives/options/options-buyer">期权买方</a></li></ul>',39)])])}const c=t(i,[["render",l]]);export{b as __pageData,c as default};
